 /* Roles/permissions/services map strictly by business key. */
 CREATE TABLE #RoleMap(source_old_id int PRIMARY KEY,final_new_id int,business_key nvarchar(600),merge_action varchar(30),conflict_reason nvarchar(1000));
 INSERT #RoleMap SELECT s.id,r.id,r.role_name,'DEDUPLICATED',NULL FROM #Srcroles s JOIN dbo.roles r ON r.role_name=s.role_name;
 INSERT dbo.roles(role_name,description) SELECT s.role_name,s.description FROM #Srcroles s WHERE NOT EXISTS(SELECT 1 FROM dbo.roles r WHERE r.role_name=s.role_name);
 INSERT #RoleMap SELECT s.id,r.id,r.role_name,'INSERTED',NULL FROM #Srcroles s JOIN dbo.roles r ON r.role_name=s.role_name WHERE NOT EXISTS(SELECT 1 FROM #RoleMap m WHERE m.source_old_id=s.id);
 CREATE TABLE #UserMap(source_old_id int PRIMARY KEY,final_new_id int,business_key nvarchar(600),merge_action varchar(30),conflict_reason nvarchar(1000));
 INSERT #UserMap SELECT s.id,u.id,COALESCE(s.username,CONVERT(nvarchar(600),s.email,1)),'DEDUPLICATED',NULL FROM #Srcusers s JOIN dbo.users u ON (s.username IS NOT NULL AND u.username=s.username) OR (s.username IS NULL AND u.email=s.email);
 INSERT dbo.users(full_name,email,password_hash,phone,role_id,status,verification_token,is_verified,google_id,auth_provider,username,is_deleted,created_at,updated_at)
 SELECT s.full_name,s.email,s.password_hash,s.phone,rm.final_new_id,s.status,s.verification_token,s.is_verified,s.google_id,s.auth_provider,s.username,s.is_deleted,s.created_at,s.updated_at FROM #Srcusers s JOIN #RoleMap rm ON rm.source_old_id=s.role_id WHERE NOT EXISTS(SELECT 1 FROM #UserMap m WHERE m.source_old_id=s.id);
 INSERT #UserMap SELECT s.id,u.id,COALESCE(s.username,CONVERT(nvarchar(600),s.email,1)),'INSERTED',NULL FROM #Srcusers s JOIN dbo.users u ON (s.username IS NOT NULL AND u.username=s.username) OR (s.username IS NULL AND u.email=s.email) WHERE NOT EXISTS(SELECT 1 FROM #UserMap m WHERE m.source_old_id=s.id);
 CREATE TABLE #PatientMap(source_old_id int PRIMARY KEY,final_new_id int,business_key nvarchar(600),merge_action varchar(30),conflict_reason nvarchar(1000));
 INSERT #PatientMap SELECT s.id,p.id,CONCAT(um.final_new_id,N'|',s.full_name,N'|',CONVERT(nvarchar(10),s.date_of_birth,23)),'DEDUPLICATED',NULL FROM #Srcpatients s LEFT JOIN #UserMap um ON um.source_old_id=s.user_id JOIN dbo.patients p ON ISNULL(p.user_id,-1)=ISNULL(um.final_new_id,-1) AND p.full_name=s.full_name AND ISNULL(p.date_of_birth,'19000101')=ISNULL(s.date_of_birth,'19000101');
 INSERT #PatientMap SELECT s.id,p.id,CONCAT(um.final_new_id,N'|',s.full_name), 'DEDUPLICATED_CONFLICT', N'Existing OCDB patient has the same mapped user_id; source profile was retained through appointment remap without overwrite.' FROM #Srcpatients s JOIN #UserMap um ON um.source_old_id=s.user_id JOIN dbo.patients p ON p.user_id=um.final_new_id WHERE NOT EXISTS(SELECT 1 FROM #PatientMap m WHERE m.source_old_id=s.id);
 INSERT #PatientMap SELECT s.id,p.id,CONCAT(N'zalo|',ISNULL(s.zalo_user_id,s.phone_number)), 'DEDUPLICATED', N'Matched existing OCDB patient by Zalo ID or phone/date of birth.' FROM #Srcpatients s JOIN dbo.patients p ON s.user_id IS NULL AND ((s.zalo_user_id IS NOT NULL AND p.zalo_user_id=s.zalo_user_id) OR (s.zalo_user_id IS NULL AND p.phone_number=s.phone_number AND ISNULL(p.date_of_birth,'19000101')=ISNULL(s.date_of_birth,'19000101'))) WHERE NOT EXISTS(SELECT 1 FROM #PatientMap m WHERE m.source_old_id=s.id);
 INSERT dbo.patients(user_id,full_name,phone_number,date_of_birth,zalo_user_id) SELECT um.final_new_id,s.full_name,s.phone_number,s.date_of_birth,s.zalo_user_id FROM #Srcpatients s LEFT JOIN #UserMap um ON um.source_old_id=s.user_id WHERE NOT EXISTS(SELECT 1 FROM #PatientMap m WHERE m.source_old_id=s.id);
 INSERT #PatientMap SELECT s.id,p.id,CONCAT(ISNULL(p.user_id,-1),N'|',p.full_name,N'|',CONVERT(nvarchar(10),p.date_of_birth,23)),'INSERTED',NULL FROM #Srcpatients s LEFT JOIN #UserMap um ON um.source_old_id=s.user_id JOIN dbo.patients p ON ISNULL(p.user_id,-1)=ISNULL(um.final_new_id,-1) AND p.full_name=s.full_name AND ISNULL(p.date_of_birth,'19000101')=ISNULL(s.date_of_birth,'19000101') WHERE NOT EXISTS(SELECT 1 FROM #PatientMap m WHERE m.source_old_id=s.id);
 CREATE TABLE #DoctorMap(source_old_id int PRIMARY KEY,final_new_id int,business_key nvarchar(600),merge_action varchar(30),conflict_reason nvarchar(1000));
 INSERT #DoctorMap SELECT s.id,d.id,s.full_name,'DEDUPLICATED',NULL FROM #Srcdoctors s JOIN #UserMap um ON um.source_old_id=s.user_id JOIN dbo.doctors d ON d.user_id=um.final_new_id OR d.full_name=s.full_name;
 INSERT dbo.doctors(user_id,full_name,specialization,phone_number) SELECT um.final_new_id,s.full_name,s.specialization,s.phone_number FROM #Srcdoctors s JOIN #UserMap um ON um.source_old_id=s.user_id WHERE NOT EXISTS(SELECT 1 FROM #DoctorMap m WHERE m.source_old_id=s.id);
 INSERT #DoctorMap SELECT s.id,d.id,d.full_name,'INSERTED',NULL FROM #Srcdoctors s JOIN #UserMap um ON um.source_old_id=s.user_id JOIN dbo.doctors d ON d.user_id=um.final_new_id WHERE NOT EXISTS(SELECT 1 FROM #DoctorMap m WHERE m.source_old_id=s.id);
 CREATE TABLE #SonographerMap(source_old_id int PRIMARY KEY,final_new_id int,business_key nvarchar(600),merge_action varchar(30),conflict_reason nvarchar(1000));
 INSERT #SonographerMap SELECT s.id,x.id,CONVERT(nvarchar(20),um.final_new_id),'DEDUPLICATED',NULL FROM #Srcsonographers s JOIN #UserMap um ON um.source_old_id=s.user_id JOIN dbo.sonographers x ON x.user_id=um.final_new_id;
 INSERT dbo.sonographers(user_id,experience_years,qualification,room_no,status) SELECT um.final_new_id,s.experience_years,s.qualification,s.room_no,s.status FROM #Srcsonographers s JOIN #UserMap um ON um.source_old_id=s.user_id WHERE NOT EXISTS(SELECT 1 FROM #SonographerMap m WHERE m.source_old_id=s.id);
 INSERT #SonographerMap SELECT s.id,x.id,CONVERT(nvarchar(20),x.user_id),'INSERTED',NULL FROM #Srcsonographers s JOIN #UserMap um ON um.source_old_id=s.user_id JOIN dbo.sonographers x ON x.user_id=um.final_new_id WHERE NOT EXISTS(SELECT 1 FROM #SonographerMap m WHERE m.source_old_id=s.id);
 CREATE TABLE #ServiceMap(source_old_id int PRIMARY KEY,final_new_id int,business_key nvarchar(600),merge_action varchar(30),conflict_reason nvarchar(1000));
 INSERT #ServiceMap SELECT s.id,f.id,f.service_code,'DEDUPLICATED',NULL FROM #Srcservices s JOIN dbo.services f ON f.service_code=s.service_code;
 CREATE TABLE #AppointmentMap(source_old_id int PRIMARY KEY,final_new_id int,business_key nvarchar(600),merge_action varchar(30),conflict_reason nvarchar(1000));
 INSERT dbo.appointments(patient_id,doctor_id,pregnancy_id,appointment_date,booking_source,symptoms,last_menstrual_period,is_emergency,status,service_id,time_slot,queue_number,slot_id)
 SELECT pm.final_new_id,dm.final_new_id,s.pregnancy_id,s.appointment_date,s.booking_source,s.symptoms,s.last_menstrual_period,s.is_emergency,s.status,sm.final_new_id,s.time_slot,s.queue_number,s.slot_id FROM #Srcappointments s JOIN #PatientMap pm ON pm.source_old_id=s.patient_id JOIN #DoctorMap dm ON dm.source_old_id=s.doctor_id LEFT JOIN #ServiceMap sm ON sm.source_old_id=s.service_id WHERE NOT EXISTS(SELECT 1 FROM dbo.appointments a WHERE a.patient_id=pm.final_new_id AND a.doctor_id=dm.final_new_id AND a.appointment_date=s.appointment_date AND ISNULL(a.time_slot,'00:00')=ISNULL(s.time_slot,'00:00') AND ISNULL(a.service_id,-1)=ISNULL(sm.final_new_id,-1));
 INSERT #AppointmentMap SELECT s.id,a.id,CONCAT(pm.final_new_id,N'|',dm.final_new_id,N'|',CONVERT(nvarchar(10),s.appointment_date,23),N'|',CONVERT(nvarchar(16),s.time_slot)),'INSERTED_OR_DEDUP',NULL FROM #Srcappointments s JOIN #PatientMap pm ON pm.source_old_id=s.patient_id JOIN #DoctorMap dm ON dm.source_old_id=s.doctor_id LEFT JOIN #ServiceMap sm ON sm.source_old_id=s.service_id JOIN dbo.appointments a ON a.patient_id=pm.final_new_id AND a.doctor_id=dm.final_new_id AND a.appointment_date=s.appointment_date AND ISNULL(a.time_slot,'00:00')=ISNULL(s.time_slot,'00:00') AND ISNULL(a.service_id,-1)=ISNULL(sm.final_new_id,-1);
 INSERT dbo.invoices(appointment_id,total_amount,status,transaction_code) SELECT am.final_new_id,s.total_amount,s.status,s.transaction_code FROM #Srcinvoices s JOIN #AppointmentMap am ON am.source_old_id=s.appointment_id WHERE NOT EXISTS(SELECT 1 FROM dbo.invoices i WHERE (s.transaction_code IS NOT NULL AND i.transaction_code=s.transaction_code) OR (s.transaction_code IS NULL AND i.appointment_id=am.final_new_id AND i.total_amount=s.total_amount));
 INSERT dbo.ocdb_merge_id_map(source_name,table_name,source_old_id,final_new_id,business_key,merge_action,conflict_reason) SELECT N'script.sql',N'users',source_old_id,final_new_id,business_key,merge_action,conflict_reason FROM #UserMap m WHERE NOT EXISTS(SELECT 1 FROM dbo.ocdb_merge_id_map x WHERE x.source_name=N'script.sql' AND x.table_name=N'users' AND x.source_old_id=m.source_old_id);
 INSERT dbo.ocdb_merge_id_map(source_name,table_name,source_old_id,final_new_id,business_key,merge_action,conflict_reason) SELECT N'script.sql',N'patients',source_old_id,final_new_id,business_key,merge_action,conflict_reason FROM #PatientMap m WHERE NOT EXISTS(SELECT 1 FROM dbo.ocdb_merge_id_map x WHERE x.source_name=N'script.sql' AND x.table_name=N'patients' AND x.source_old_id=m.source_old_id);
 INSERT dbo.ocdb_merge_id_map(source_name,table_name,source_old_id,final_new_id,business_key,merge_action,conflict_reason) SELECT N'script.sql',N'doctors',source_old_id,final_new_id,business_key,merge_action,conflict_reason FROM #DoctorMap m WHERE NOT EXISTS(SELECT 1 FROM dbo.ocdb_merge_id_map x WHERE x.source_name=N'script.sql' AND x.table_name=N'doctors' AND x.source_old_id=m.source_old_id);
 INSERT dbo.ocdb_merge_id_map(source_name,table_name,source_old_id,final_new_id,business_key,merge_action,conflict_reason) SELECT N'script.sql',N'appointments',source_old_id,final_new_id,business_key,merge_action,conflict_reason FROM #AppointmentMap m WHERE NOT EXISTS(SELECT 1 FROM dbo.ocdb_merge_id_map x WHERE x.source_name=N'script.sql' AND x.table_name=N'appointments' AND x.source_old_id=m.source_old_id);
 INSERT dbo.ocdb_merge_unresolved(source_name,table_name,source_old_id,business_key,missing_relation,candidate_mappings) SELECT N'script.sql',N'appointments',s.id,CONCAT(s.patient_id,N'|',s.doctor_id),N'Patient, doctor, or service business-key map not found',NULL FROM #Srcappointments s LEFT JOIN #AppointmentMap m ON m.source_old_id=s.id WHERE m.source_old_id IS NULL AND NOT EXISTS(SELECT 1 FROM dbo.ocdb_merge_unresolved u WHERE u.source_name=N'script.sql' AND u.table_name=N'appointments' AND u.source_old_id=s.id);
 /* Application RBAC baseline: Manager schedule approval and time-slot management. */
 IF NOT EXISTS (SELECT 1 FROM dbo.permissions WHERE permission_key=N'schedule.view')
     INSERT dbo.permissions(permission_key,permission_name,module,description,created_at)
     VALUES (N'schedule.view',N'View and manage doctor schedules',N'schedules',N'Approve doctor schedules and manage examination time slots.',SYSUTCDATETIME());
 IF NOT EXISTS (
     SELECT 1 FROM dbo.role_permissions rp
     JOIN dbo.roles r ON r.id=rp.role_id
     JOIN dbo.permissions p ON p.id=rp.permission_id
     WHERE r.role_name=N'Manager' AND p.permission_key=N'schedule.view'
 )
     INSERT dbo.role_permissions(role_id,permission_id)
     SELECT r.id,p.id FROM dbo.roles r CROSS JOIN dbo.permissions p
     WHERE r.role_name=N'Manager' AND p.permission_key=N'schedule.view';
 /* Repair pre-existing OCDB role/profile inconsistency.  A user who is active
    as Doctor must have a doctors row before Doctor controllers can operate. */
 INSERT dbo.doctors(user_id,full_name,phone_number,specialization)
 SELECT u.id,u.full_name,NULL,NULL
 FROM dbo.users u
 LEFT JOIN dbo.doctors d ON d.user_id=u.id
 WHERE u.role_id=2
   AND u.status=N'Active'
   AND ISNULL(u.is_deleted,0)=0
   AND d.id IS NULL;
 INSERT dbo.sonographers(user_id,status)
 SELECT u.id,N'Active'
 FROM dbo.users u
 LEFT JOIN dbo.sonographers s ON s.user_id=u.id
 WHERE u.role_id=6
   AND u.status=N'Active'
   AND ISNULL(u.is_deleted,0)=0
   AND s.id IS NULL;
 COMMIT TRANSACTION; PRINT N'[merge] completed staged remap';
END TRY
BEGIN CATCH
 IF XACT_STATE()<>0 ROLLBACK TRANSACTION; THROW;
END CATCH;
GO
SET IDENTITY_INSERT #Srcaudit_logs OFF;

/* Retire the laboratory feature after merge completion. */

SET NOCOUNT ON;
SET XACT_ABORT ON;

BEGIN TRY
    BEGIN TRANSACTION;

    DECLARE @LabServices TABLE (id INT NOT NULL PRIMARY KEY);
    INSERT INTO @LabServices (id)
    SELECT s.id
    FROM dbo.services AS s
    INNER JOIN dbo.service_categories AS c ON c.id = s.category_id
    WHERE c.category_name = N'Xét nghiệm'
       OR s.service_code LIKE N'SVC-XN-%';

    DECLARE @LabAppointments TABLE (id INT NOT NULL PRIMARY KEY);
    INSERT INTO @LabAppointments (id)
    SELECT a.id
    FROM dbo.appointments AS a
    INNER JOIN @LabServices AS s ON s.id = a.service_id;

    DECLARE @LabInvoices TABLE (id INT NOT NULL PRIMARY KEY);
    INSERT INTO @LabInvoices (id)
    SELECT i.id
    FROM dbo.invoices AS i
    INNER JOIN @LabAppointments AS a ON a.id = i.appointment_id;

    DECLARE @LabOrders TABLE (id INT NOT NULL PRIMARY KEY);
    INSERT INTO @LabOrders (id)
    SELECT t.id
    FROM dbo.test_orders AS t
    INNER JOIN @LabServices AS s ON s.id = t.service_id;

    /* Delete dependent records before their parent appointment/order/service. */
    DELETE ii
    FROM dbo.invoice_items AS ii
    INNER JOIN @LabInvoices AS i ON i.id = ii.invoice_id;

    DELETE i
    FROM dbo.invoices AS i
    INNER JOIN @LabInvoices AS li ON li.id = i.id;

    DELETE r
    FROM dbo.reviews AS r
    INNER JOIN @LabAppointments AS a ON a.id = r.appointment_id;

    DELETE air
    FROM dbo.ai_analysis_results AS air
    INNER JOIN @LabOrders AS o ON o.id = air.test_order_id;

    DELETE ui
    FROM dbo.ultrasound_images AS ui
    INNER JOIN @LabOrders AS o ON o.id = ui.test_order_id;

    IF OBJECT_ID(N'dbo.lab_results', N'U') IS NOT NULL
    BEGIN
        DELETE lr
        FROM dbo.lab_results AS lr
        INNER JOIN @LabOrders AS o ON o.id = lr.test_order_id;
    END;

    DELETE t
    FROM dbo.test_orders AS t
    INNER JOIN @LabOrders AS o ON o.id = t.id;

    DELETE ph
    FROM dbo.price_history AS ph
    INNER JOIN @LabServices AS s ON s.id = ph.service_id;

    DELETE a
    FROM dbo.appointments AS a
    INNER JOIN @LabAppointments AS la ON la.id = a.id;

    DELETE n
    FROM dbo.notifications AS n
    WHERE n.title LIKE N'%Xét nghiệm%'
       OR n.content LIKE N'%Xét nghiệm%';

    DELETE al
    FROM dbo.audit_logs AS al
    WHERE al.table_name = N'lab_results'
       OR al.old_value LIKE N'%Lab Technician%'
       OR al.new_value LIKE N'%Lab Technician%'
       OR al.old_value LIKE N'%Xét nghiệm%'
       OR al.new_value LIKE N'%Xét nghiệm%';

    DELETE s
    FROM dbo.services AS s
    INNER JOIN @LabServices AS ls ON ls.id = s.id;

    DELETE FROM dbo.service_categories
    WHERE category_name = N'Xét nghiệm'
      AND NOT EXISTS (
          SELECT 1 FROM dbo.services AS s
          WHERE s.category_id = dbo.service_categories.id
      );

    DELETE rp
    FROM dbo.role_permissions AS rp
    INNER JOIN dbo.roles AS r ON r.id = rp.role_id
    WHERE r.role_name = N'Lab Technician';

    IF EXISTS (
        SELECT 1
        FROM dbo.users AS u
        INNER JOIN dbo.roles AS r ON r.id = u.role_id
        WHERE r.role_name = N'Lab Technician'
    )
    BEGIN
        THROW 51000, 'Lab Technician users still exist. Move or remove those users explicitly before removing the role.', 1;
    END;

    DELETE FROM dbo.roles WHERE role_name = N'Lab Technician';

    IF OBJECT_ID(N'dbo.lab_results', N'U') IS NOT NULL
        DROP TABLE dbo.lab_results;

    IF EXISTS (SELECT 1 FROM dbo.roles WHERE role_name = N'Lab Technician')
        THROW 51001, 'Lab Technician role cleanup failed.', 1;

    IF EXISTS (SELECT 1 FROM dbo.services WHERE service_code LIKE N'SVC-XN-%')
        THROW 51002, 'Laboratory service cleanup failed.', 1;

    IF EXISTS (SELECT 1 FROM dbo.service_categories WHERE category_name = N'Xét nghiệm')
        THROW 51003, 'Laboratory category cleanup failed.', 1;

    COMMIT TRANSACTION;

    SELECT
        (SELECT COUNT(*) FROM dbo.roles WHERE role_name = N'Lab Technician') AS remaining_lab_roles,
        (SELECT COUNT(*) FROM dbo.services WHERE service_code LIKE N'SVC-XN-%') AS remaining_lab_services,
        (SELECT COUNT(*) FROM dbo.service_categories WHERE category_name = N'Xét nghiệm') AS remaining_lab_categories,
        (SELECT COUNT(*) FROM dbo.appointments) AS final_appointments,
        (SELECT COUNT(*) FROM dbo.invoices) AS final_invoices;
END TRY
BEGIN CATCH
    IF XACT_STATE() <> 0 ROLLBACK TRANSACTION;
    THROW;
END CATCH;
GO

/* The OCDB baseline assigns the retired laboratory category ID 3. */
IF EXISTS (SELECT 1 FROM dbo.services WHERE category_id = 3)
    THROW 51004, 'Retired category ID 3 still has services; cleanup stopped.', 1;
DELETE FROM dbo.service_categories WHERE id = 3;
IF EXISTS (SELECT 1 FROM dbo.service_categories WHERE id = 3)
    THROW 51005, 'Retired laboratory category ID 3 cleanup failed.', 1;
GO
